#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_PLANETS 1024
#define MAX_CONNECTIONS 40000

// Structure to represent a planet
typedef struct Planet {
    int id;
    int connections[MAX_PLANETS];
} Planet;

// Function to create a new planet
Planet* createPlanet(int id) {
    Planet* planet = (Planet*)malloc(sizeof(Planet));
    planet->id = id;
    for (int i = 0; i < MAX_PLANETS; i++) {
        planet->connections[i] = 0;
    }
    return planet;
}

// Function to add a connection between two planets
void addConnection(Planet* planet1, Planet* planet2) {
    planet1->connections[planet2->id] = 1;
    planet2->connections[planet1->id] = 1;
}

// Function to check if a galaxy is a good galaxy
int isGoodGalaxy(Planet* planets, int numPlanets, int numConnections) {
    // Check if the galaxy is connected
    for (int i = 0; i < numPlanets; i++) {
        for (int j = i + 1; j < numPlanets; j++) {
            if (planets[i].connections[j] == 0) {
                return 0;
            }
        }
    }

    // Check if the galaxy has a diameter of 2
    for (int i = 0; i < numPlanets; i++) {
        for (int j = i + 1; j < numPlanets; j++) {
            if (planets[i].connections[j] == 0) {
                for (int k = 0; k < numPlanets; k++) {
                    if (planets[i].connections[k] == 1 && planets[k].connections[j] == 1) {
                        return 0;
                    }
                }
            }
        }
    }

    return 1;
}

int main() {
    int T;
    scanf("%d", &T);

    for (int t = 0; t < T; t++) {
        int N, M;
        scanf("%d %d", &N, &M);

        Planet* planets = (Planet*)malloc(N * sizeof(Planet));
        for (int i = 0; i < N; i++) {
            planets[i] = *createPlanet(i);
        }

        for (int i = 0; i < M; i++) {
            int planet1, planet2;
            scanf("%d %d", &planet1, &planet2);
            addConnection(&planets[planet1 - 1], &planets[planet2 - 1]);
        }

        if (isGoodGalaxy(planets, N, M)) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }

        free(planets);
    }

    return 0;
}

