using namespace std;

// Structure to represent a planet
struct Planet {
    int id;
    vector<int> connections;
};

// Function to create a new planet
Planet createPlanet(int id) {
    Planet planet;
    planet.id = id;
    return planet;
}

// Function to add a connection between two planets
void addConnection(Planet& planet1, Planet& planet2) {
    planet1.connections.push_back(planet2.id);
    planet2.connections.push_back(planet1.id);
}

// Function to check if a galaxy is a good galaxy
bool isGoodGalaxy(vector<Planet>& planets) {
    // Check if the galaxy is connected
    for (int i = 0; i < planets.size(); i++) {
        for (int j = i + 1; j < planets.size(); j++) {
            if (find(planets[i].connections.begin(), planets[i].connections.end(), planets[j].id) == planets[i].connections.end()) {
                return false;
            }
        }
    }

    // Check if the galaxy has a diameter of 2
    for (int i = 0; i < planets.size(); i++) {
        for (int j = i + 1; j < planets.size(); j++) {
            if (find(planets[i].connections.begin(), planets[i].connections.end(), planets[j].id) == planets[i].connections.end()) {
                for (int k = 0; k < planets.size(); k++) {
                    if (find(planets[i].connections.begin(), planets[i].connections.end(), planets[k].id) != planets[i].connections.end() && find(planets[k].connections.begin(), planets[k].connections.end(), planets[j].id) != planets[k].connections.end()) {
                        return false;
                    }
                }
            }
        }
    }

    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;

    for (int t = 0; t < T; t++) {
        int N, M;
        cin >> N >> M;

        vector<Planet> planets;
        for (int i = 0; i < N; i++) {
            planets.push_back(createPlanet(i));
        }

        for (int i = 0; i < M; i++) {
            int planet1, planet2;
            cin >> planet1 >> planet2;
            addConnection(planets[planet1 - 1], planets[planet2 - 1]);
        }

        if (isGoodGalaxy(planets)) {
            cout << "YES" << endl;
        } else {
            cout << "NO" << endl;
        }
    }

    return 0;
}

