import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    // Structure to represent a planet
    static class Planet {
        int id;
        ArrayList<Integer> connections;

        public Planet(int id) {
            this.id = id;
            this.connections = new ArrayList<>();
        }
    }

    // Function to add a connection between two planets
    public static void addConnection(Planet planet1, Planet planet2) {
        planet1.connections.add(planet2.id);
        planet2.connections.add(planet1.id);
    }

    // Function to check if a galaxy is a good galaxy
    public static boolean isGoodGalaxy(Planet[] planets) {
        // Check if the galaxy is connected
        for (int i = 0; i < planets.length; i++) {
            for (int j = i + 1; j < planets.length; j++) {
                if (!planets[i].connections.contains(planets[j].id)) {
                    return false;
                }
            }
        }

        // Check if the galaxy has a diameter of 2
        for (int i = 0; i < planets.length; i++) {
            for (int j = i + 1; j < planets.length; j++) {
                if (!planets[i].connections.contains(planets[j].id)) {
                    for (int k = 0; k < planets.length; k++) {
                        if (planets[i].connections.contains(planets[k].id) && planets[k].connections.contains(planets[j].id)) {
                            return false;
                        }
                    }
                }
            }
        }

        return true;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();

        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();

            Planet[] planets = new Planet[N];
            for (int i = 0; i < N; i++) {
                planets[i] = new Planet(i);
            }

            for (int i = 0; i < M; i++) {
                int planet1 = scanner.nextInt();
                int planet2 = scanner.nextInt();
                addConnection(planets[planet1 - 1], planets[planet2 - 1]);
            }

            if (isGoodGalaxy(planets)) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

